import{_ as o,o as a,c as s,a0 as n}from"./chunks/framework.CSK6mTG2.js";const g=JSON.parse('{"title":"解码策略：如何\\"选词\\"决定输出质量","description":"","frontmatter":{},"headers":[],"relativePath":"menuAI/decoding-strategies.md","filePath":"menuAI/decoding-strategies.md"}'),e={name:"menuAI/decoding-strategies.md"};function p(l,t,i,r,u,d){return a(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="解码策略-如何-选词-决定输出质量" tabindex="-1">解码策略：如何&quot;选词&quot;决定输出质量 <a class="header-anchor" href="#解码策略-如何-选词-决定输出质量" aria-label="Permalink to &quot;解码策略：如何&quot;选词&quot;决定输出质量&quot;">​</a></h1><blockquote><p>大模型吐出一个字还是吐出一句话，背后是一套关于&quot;怎么选&quot;的算法博弈。</p></blockquote><hr><h2 id="开头-一个字怎么蹦出来的" tabindex="-1">开头：一个字怎么蹦出来的 <a class="header-anchor" href="#开头-一个字怎么蹦出来的" aria-label="Permalink to &quot;开头：一个字怎么蹦出来的&quot;">​</a></h2><p>你有没有想过，当你对大模型说&quot;写一首诗&quot;，它是怎么一个字一个字往外&quot;吐&quot;的？</p><p>说白了就是<strong>循环预测</strong>：每生成一个新词，就把前面生成的所有词当成&quot;提示&quot;，让模型重新算一遍——下一个词最可能是什么。这个过程叫做<strong>自回归生成（Autoregressive Generation）</strong>，就像你玩猜词游戏，每次给一个提示，你猜一个词，下一轮再根据这个词继续猜。</p><p>但问题来了：<strong>每次猜词的时候，候选词可能有很多个，模型给每个候选词都打了个分（概率），怎么从这些候选词里挑一个？</strong></p><p>这就是解码策略要解决的问题。不同的选法，出来的文字质量天差地别。</p><hr><h2 id="贪婪解码-永远选-最优-的那个" tabindex="-1">贪婪解码：永远选&quot;最优&quot;的那个 <a class="header-anchor" href="#贪婪解码-永远选-最优-的那个" aria-label="Permalink to &quot;贪婪解码：永远选&quot;最优&quot;的那个&quot;">​</a></h2><p>最直观的做法：<strong>每次选概率最高的那个词</strong>。这叫<strong>贪婪解码（Greedy Decoding）</strong>。</p><p>想象你站在一个分岔路口，每条路都标着&quot;这条路通向正确答案的概率&quot;。贪婪的人就是：哪条路概率最高就走哪条，不回头。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模型说：&quot;床前明&quot; → &quot;月&quot;（概率最高 0.95）→ &quot;光&quot;（0.92）→ &quot;疑&quot;（0.88）→ ...</span></span></code></pre></div><p><strong>优点</strong>：</p><ul><li>简单高效，每次只算一次选择</li><li>结果确定性高，不会随机跳脱</li></ul><p><strong>致命缺点</strong>： 这就像一个从来不走回头路的人，一旦选错了一条岔道，就再也到不了真正的目的地。在文字生成里，这意味着——</p><blockquote><p>贪婪解码容易陷入<strong>局部最优陷阱</strong>。它会反复生成&quot;安全的废话&quot;，比如 ChatGPT 早期的&quot;综上所述&quot;&quot;首先其次最后&quot;——因为这些词的概率确实高，但满屏都是就无聊了。</p></blockquote><p><strong>什么时候用它</strong>：对速度要求极高、质量要求一般的场景（比如填空、检索排序）。</p><hr><h2 id="束搜索-同时走n条路" tabindex="-1">束搜索：同时走N条路 <a class="header-anchor" href="#束搜索-同时走n条路" aria-label="Permalink to &quot;束搜索：同时走N条路&quot;">​</a></h2><p>束搜索（Beam Search）的思路是：<strong>别只留一条路，留N条&quot;最有可能的路&quot;一起走</strong>。</p><p>你可以理解为：你派了N个探险队同时出发，每到分岔路口，每个队伍都只保留自己这条路上概率最高的分支。这样既能探索更多可能性，又不会像完全随机采样那样跑偏。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Beam Size = 3（同时走3条路）</span></span>
<span class="line"><span>第1步：[&quot;床&quot;(0.95), &quot;桌&quot;(0.03), &quot;楼&quot;(0.02)] → 保留前3</span></span>
<span class="line"><span>第2步：分别扩展，找到每条路的最佳下一词 → 保留综合评分前3的路径</span></span>
<span class="line"><span>...</span></span></code></pre></div><p><strong>为什么叫&quot;束（Beam）&quot;</strong>：可以想象成一个扇形的搜索窗口，像手电筒的束光一样，照亮的范围有限，但比一根针宽。</p><p><strong>实际效果</strong>：</p><ul><li>生成质量通常比贪婪好很多</li><li>是大多数翻译、摘要系统的默认选择</li><li>平衡了质量和效率</li></ul><p><strong>注意</strong>：Beam Size 越大，结果越好吗？不一定。太大的束宽会让生成变得保守——因为所有分支都在追求&quot;安全的高概率词&quot;，反而丢失了创造性。</p><hr><h2 id="采样-从-确定性-到-掷骰子" tabindex="-1">采样：从&quot;确定性&quot;到&quot;掷骰子&quot; <a class="header-anchor" href="#采样-从-确定性-到-掷骰子" aria-label="Permalink to &quot;采样：从&quot;确定性&quot;到&quot;掷骰子&quot;&quot;">​</a></h2><p>到这里你可能发现了：贪婪和束搜索都是<strong>确定性</strong>的——同样的输入，永远得到同样的输出（或者只有微小变体）。这在很多场景下是好的，但用来对话、写故事、生成代码就太无聊了。</p><p>于是引入了<strong>采样（Sampling）</strong>：按概率大小来&quot;掷骰子&quot;选词。</p><h3 id="为什么按概率" tabindex="-1">为什么按概率？ <a class="header-anchor" href="#为什么按概率" aria-label="Permalink to &quot;为什么按概率？&quot;">​</a></h3><p>简单理解：模型给&quot;月&quot;打了95%的分，给&quot;桌&quot;打了3%，给&quot;楼&quot;打了2%——那就让&quot;月&quot;有95%的概率被选到，而不是绝对地选它。掷骰子的结果虽然有随机性，但长期来看概率分布是不变的。</p><p>这样文字就有了<strong>变化和创意</strong>：同一句诗的提示，今天可能生成&quot;床前明月光&quot;，明天可能生成&quot;床前明月光&quot;，但偶尔也会生成不那么&quot;正确&quot;但更有创意的词。</p><hr><h2 id="top-k-采样-只允许骰子落在-前k名" tabindex="-1">Top-k 采样：只允许骰子落在&quot;前K名&quot; <a class="header-anchor" href="#top-k-采样-只允许骰子落在-前k名" aria-label="Permalink to &quot;Top-k 采样：只允许骰子落在&quot;前K名&quot;&quot;">​</a></h2><p>纯采样有个问题：如果概率分布很平（比如每个候选词概率都是1%、2%），骰子可能会掷出一个完全离谱的词——虽然概率低，但终究可能被选中。</p><p><strong>Top-k 采样</strong>就是在掷骰子之前先做一次筛选：<strong>只保留概率最高的前K个词，其余的直接忽略</strong>，然后在这K个词里按概率采样。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>候选词概率：[月:0.35, 光:0.25, 霜:0.15, 雪:0.10, 星:0.08, ...]</span></span>
<span class="line"><span>Top-k = 3 → 只看 [月, 光, 霜]，再按概率分配骰子</span></span>
<span class="line"><span>→ 月的概率 = 0.35/(0.35+0.25+0.15) ≈ 47%</span></span></code></pre></div><p><strong>k 设成多少合适</strong>：</p><ul><li>k 太小（比如 k=1）→ 等同于贪婪，容易重复</li><li>k 太大（比如 k=10000）→ 接近纯采样，可能跳词</li><li>实际经验：k=20~100 是常见区间</li></ul><p><strong>适合场景</strong>：需要多样性的创意写作、头脑风暴式对话。</p><hr><h2 id="top-p-核采样-更动态的-骰子范围" tabindex="-1">Top-p（核采样）：更动态的&quot;骰子范围&quot; <a class="header-anchor" href="#top-p-核采样-更动态的-骰子范围" aria-label="Permalink to &quot;Top-p（核采样）：更动态的&quot;骰子范围&quot;&quot;">​</a></h2><p>Top-k 有一个硬伤：<strong>不管候选词分布是陡峭还是平坦，K都是固定的</strong>。</p><p>想象两种情况：</p><ol><li>模型非常有把握：概率集中在前3个词 [0.95, 0.03, 0.01]</li><li>模型很纠结：概率平摊在前100个词 [0.02, 0.019, 0.018, ...]</li></ol><p>用同样的 k=50，第一种情况下会混入大量低概率词，第二种情况下会筛掉很多其实也合理的词。</p><p><strong>Top-p（也叫 Nucleus Sampling）</strong> 就是来解决这个问题的：</p><blockquote><p>不是固定选前K个，而是<strong>从概率最高的词开始往下累加，累加到概率之和超过阈值 p（比如0.9），就停</strong>。这个动态的候选集合叫&quot;核（nucleus）&quot;。</p></blockquote><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>p = 0.9</span></span>
<span class="line"><span>候选：[月:0.35, 光:0.25, 霜:0.15, 雪:0.10, 星:0.08, 风:0.04, ...]</span></span>
<span class="line"><span>累加：0.35 → 0.60 → 0.75 → 0.85 → 0.93 → 超过0.9！</span></span>
<span class="line"><span>→ 核集合 = [月, 光, 霜, 雪]（这4个词的累积概率刚好超过90%）</span></span>
<span class="line"><span>→ 只在这4个词里按概率采样</span></span></code></pre></div><p><strong>为什么更好</strong>：</p><ul><li>模型自信时，核很小，输出稳定</li><li>模型纠结时，核变大，允许更多变化</li><li>自适应地平衡&quot;质量&quot;和&quot;多样性&quot;</li></ul><p>这是目前<strong>最主流的采样策略</strong>，大多数产品级对话都默认用 Top-p。</p><hr><h2 id="温度-控制骰子的-偏心程度" tabindex="-1">温度：控制骰子的&quot;偏心程度&quot; <a class="header-anchor" href="#温度-控制骰子的-偏心程度" aria-label="Permalink to &quot;温度：控制骰子的&quot;偏心程度&quot;&quot;">​</a></h2><p>最后来说一个控制&quot;随机性&quot;的全局旋钮——<strong>温度（Temperature）</strong>。</p><p>温度这个概念来自统计力学。放到语言模型里，它的作用是<strong>调整概率分布的&quot;尖锐程度&quot;</strong>：</p><ul><li><strong>T = 1.0</strong>：概率分布不变，完全按模型原意采样</li><li><strong>T &lt; 1.0</strong>（比如0.7）：<strong>概率分布变陡峭</strong>——高分词概率更高，低分词概率被压低。输出更确定、更保守、更像&quot;正确答案&quot;</li><li><strong>T &gt; 1.0</strong>（比如1.5）：<strong>概率分布变平坦</strong>——各个词的概率差距缩小，骰子更容易掷到&quot;意外&quot;的词。输出更有创意，但也可能更离谱</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始概率：[月:0.95, 光:0.03, 雪:0.01]</span></span>
<span class="line"><span>经过 softmax 温度调整后：</span></span>
<span class="line"><span>T=0.5 → [月:0.999, 光:0.001, 雪:0.0001] → 几乎只会选月</span></span>
<span class="line"><span>T=1.5 → [月:0.85, 光:0.10, 雪:0.04] → 偶尔能跳出月</span></span></code></pre></div><p><strong>实际应用建议</strong>：</p><ul><li>写代码、做推理、事实问答 → 低温度（0.3~0.7）</li><li>聊天、头脑风暴、创意写作 → 中温度（0.7~1.0）</li><li>要求极度多样性（比如生成多种备选方案） → 高温度（1.0~1.5）</li></ul><p>大多数 API（比如 OpenAI）把温度参数暴露给用户，让你自己调旋钮。</p><hr><h2 id="解码策略组合使用" tabindex="-1">解码策略组合使用 <a class="header-anchor" href="#解码策略组合使用" aria-label="Permalink to &quot;解码策略组合使用&quot;">​</a></h2><p>实际产品里，这些策略往往是<strong>组合使用</strong>的：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Top-p = 0.9, Temperature = 0.8</span></span>
<span class="line"><span>= 先用温度调整概率分布，再用 Top-p 动态选候选池，最后在池内采样</span></span></code></pre></div><p>这种组合是目前 GPT-4、Claude 等主流模型对话时的默认配置。</p><p>还有两个值得了解的补充策略：</p><ul><li><strong>重复惩罚（Repetition Penalty）</strong>：如果某个词被重复使用，降低它后续被选中的概率，解决&quot;大模型复读机&quot;问题</li><li><strong>长度惩罚（Length Penalty）</strong>：防止束搜索偏向生成过短或过长的句子</li></ul><hr><h2 id="总结-一场-质量-vs-多样性-的博弈" tabindex="-1">总结：一场&quot;质量 vs 多样性&quot;的博弈 <a class="header-anchor" href="#总结-一场-质量-vs-多样性-的博弈" aria-label="Permalink to &quot;总结：一场&quot;质量 vs 多样性&quot;的博弈&quot;">​</a></h2><p>解码策略的核心矛盾其实很简单：</p><table tabindex="0"><thead><tr><th>策略</th><th>质量倾向</th><th>多样性</th><th>速度</th></tr></thead><tbody><tr><td>贪婪</td><td>稳定但保守</td><td>低</td><td>最快</td></tr><tr><td>束搜索</td><td>较好</td><td>中</td><td>快</td></tr><tr><td>Top-k 采样</td><td>依赖k设置</td><td>可调</td><td>快</td></tr><tr><td>Top-p + 温度</td><td>最好（通常）</td><td>最灵活</td><td>快</td></tr></tbody></table><p>没有绝对的&quot;最好&quot;，只有&quot;最适合当前场景&quot;。写代码追求稳定准确，头脑风暴追求出其不意——<strong>你拧的旋钮，决定了模型是&quot;一本正经的专家&quot;还是&quot;天马行空的诗人&quot;</strong>。</p><p>理解这些解码策略，下次你调 API 的 temperature 参数，或者看到模型输出&quot;太保守/太跳脱&quot;时，就能知道问题出在哪里了。</p>`,76)])])}const h=o(e,[["render",p]]);export{g as __pageData,h as default};
